#include <stdio.h>
int main() {
    int N;
    scanf("%d", &N);
    for (int i = 0; i < N; i++) {
        int count = 0;
        for (int j = 0; j < 5; j++) {
            int result;
            scanf("%d", &result);
            count += result;
        }
        if (count == 0) printf("Beginner\n");
        else if (count == 1) printf("Junior Developer\n");
        else if (count == 2) printf("Middle Developer\n");
        else if (count == 3) printf("Senior Developer\n");
        else if (count == 4) printf("Hacker\n");
        else if (count == 5) printf("Jeff Dean\n");
    }
    return 0;
}

